SELECT volcano_name
  FROM volcanoes
  WHERE region = 'Indonesia';

SELECT COUNT(eruption_id) AS eruption_count
FROM eruptions
WHERE volcano_id = 0;

SELECT volcano_name, last_eruption_date
FROM volcanoes
WHERE last_eruption_date = (SELECT MAX(last_eruption_date) FROM volcanoes);

SELECT eruption_type
FROM eruptions
WHERE eruption_type = 'shallow volcanic';

SELECT volcano_id, COUNT(eruption_id) AS eruption_count
FROM eruptions
GROUP BY volcano_id;

SELECT volcano_name
FROM volcanoes
ORDER BY volcano_name;
